export const parseRawServerToggleOptionValue = (value) => {
    if (typeof value !== 'string')
        return;
    return value !== '0';
};
export const normalizeServerToggleOptionValue = (value, option) => value ?? option.def;
export const serializeServerToggleOptionValue = (value) => `${+value}`;
export const toServerToggleOption = (localize, query, option) => ({
    query,
    name: localize(option.name),
    description: option.description && localize(option.description),
    required: option.required,
    type: option.type,
    def: option.def,
});
